1	type QuoteStep = { op: "quote"; items: Array<{ type: string }> };
2	type Scenario = { customer: { yearsWithMHPCO: number }; steps: QuoteStep[] };
3	type QuoteResult = { premium: number };
4	
5	const PROCESSING_FEE = 5;
6	const FIRST_INSURANCE_RATE = 0.1;
7	
8	const ITEM_BASE_PREMIUMS: Record<string, number> = {
9	  sword: 100,
10	  amulet: 60,
11	  staff: 80,
12	  potion: 40,
13	  rune: 25,
14	};
15	
16	const premiumFor = (totalBase: number): number =>
17	  totalBase + Math.ceil(totalBase * FIRST_INSURANCE_RATE) + PROCESSING_FEE;
18	
19	const baseFor = (item: { type: string }): number => ITEM_BASE_PREMIUMS[item.type];
20	
21	const quoteFor = (step: QuoteStep): QuoteResult => ({
22	  premium: premiumFor(step.items.reduce((sum, item) => sum + baseFor(item), 0)),
23	});
24	
25	export const processScenario = (input: Scenario): { results: QuoteResult[] } => {
26	  return { results: input.steps.map(quoteFor) };
27	};
28

