const baseFor = (item: { type: string }): number => ITEM_BASE_PREMIUMS[item.type];

const totalBaseFor = (items: Array<{ type: string }>): number =>
  items.reduce((sum, item) => sum + baseFor(item), 0);

const quoteFor = (step: QuoteStep): QuoteResult => ({
  premium: premiumFor(totalBaseFor(step.items)),
});
